struct DemoMapView: UIViewRepresentable {
    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 11)
        let mapView = GMSMapView(frame: .zero, camera: camera)

        let locations = [
            ("HQ", 37.7749, -122.4194),
            ("Customer A", 37.7849, -122.4094),
            ("Customer B", 37.7649, -122.4294)
        ]

        for item in locations {
            let marker = GMSMarker()
            marker.position = CLLocationCoordinate2D(latitude: item.1, longitude: item.2)
            marker.title = item.0
            marker.map = mapView
        }

        let path = GMSMutablePath()
        locations.forEach { path.add(CLLocationCoordinate2D(latitude: $0.1, longitude: $0.2)) }

        let polyline = GMSPolyline(path: path)
        polyline.strokeWidth = 4
        polyline.strokeColor = .systemBlue
        polyline.map = mapView

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {}
}

struct CardEntryView: UIViewRepresentable {
    @Binding var cardParams: STPPaymentMethodCardParams

    func makeCoordinator() -> Coordinator {
        Coordinator(cardParams: $cardParams)
    }

    func makeUIView(context: Context) -> STPPaymentCardTextField {
        let textField = STPPaymentCardTextField()
        textField.delegate = context.coordinator
        return textField
    }

    func updateUIView(_ uiView: STPPaymentCardTextField, context: Context) {}

    final class Coordinator: NSObject, STPPaymentCardTextFieldDelegate {
        @Binding var cardParams: STPPaymentMethodCardParams

        init(cardParams: Binding<STPPaymentMethodCardParams>) {
            _cardParams = cardParams
        }

        func paymentCardTextFieldDidChange(_ textField: STPPaymentCardTextField) {
            cardParams.number = textField.cardNumber
            cardParams.expMonth = UInt(textField.expirationMonth)
            cardParams.expYear = UInt(textField.expirationYear)
            cardParams.cvc = textField.cvc
        }
    }
}

struct PaymentDemoView: View {
    let amount: Int
    let cardParams: STPPaymentMethodCardParams
    let billingName: String
    let billingEmail: String
    let onComplete: (String) -> Void

    @Environment(\.dismiss) private var dismiss
    @State private var isProcessing = false
    @State private var resultMessage = "Ready to simulate payment"

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Text("Demo Payment")
                    .font(.title.bold())

                Text("Amount: \(formattedAmount(amount))")
                    .font(.headline)

                Text(resultMessage)
                    .multilineTextAlignment(.center)
                    .foregroundColor(.secondary)
                    .padding(.horizontal)

                Button(action: processDemoPayment) {
                    if isProcessing {
                        ProgressView()
                            .frame(maxWidth: .infinity)
                            .padding()
                    } else {
                        Text("Confirm Payment")
                            .font(.headline)
                            .frame(maxWidth: .infinity)
                            .padding()
                    }
                }
                .disabled(isProcessing)
                .background(isProcessing ? Color.gray.opacity(0.3) : Color.green)
                .foregroundColor(.white)
                .cornerRadius(12)
                .padding(.horizontal)

                Button("Close") {
                    dismiss()
                }
                .padding(.top, 8)

                Spacer()
            }
            .padding(.top, 40)
            .navigationTitle("Stripe Demo")
        }
    }

    private func processDemoPayment() {
        isProcessing = true
        resultMessage = "Processing with Stripe test configuration..."

        let billingDetails = STPPaymentMethodBillingDetails()
        billingDetails.name = billingName.isEmpty ? "Demo User" : billingName
        billingDetails.email = billingEmail.isEmpty ? "demo@example.com" : billingEmail

        let paymentMethodParams = STPPaymentMethodParams(card: cardParams, billingDetails: billingDetails, metadata: nil)

        STPAPIClient.shared.createPaymentMethod(with: paymentMethodParams) { paymentMethod, error in
            DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
                isProcessing = false
                if let error = error {
                    resultMessage = "Payment method failed: \(error.localizedDescription)"
                    onComplete("Failed")
                } else if paymentMethod != nil {
                    resultMessage = "Demo payment successful. Payment method created."
                    onComplete("Success")
                } else {
                    resultMessage = "Demo payment completed with simulated success."
                    onComplete("Success")
                }
            }
        }
    }

    private func formattedAmount(_ cents: Int) -> String {
        String(format: "$%.2f", Double(cents) / 100.0)
    }
}